import React, {useRef, useState, useEffect} from 'react'
import styled from 'styled-components'
import Header from '../components/Header'
import Navbar from '../components/Navbar'
import SingleOrderSection from '../components/SingleOrderSection'
import {} from '../WebAPI.js'


const ShoppingCartWrapper = styled.div `
display:flex;
width:80%;
margin:60px auto;
justify-content:space-between;
align-items:center;
`

const ItemsPart = styled.div `
width:700px;
`

const InfoPart = styled.div `
width:400px;
`

const ItemsWrapper = styled.div `
display:flex;
flex-direction:column;
width:100%;
`

const Item = styled.div `
width:100%;
height:140px;
border-top:1px solid rgb(200, 200, 200);
border-bottom:1px solid rgb(200, 200, 200);
font-size:0.9rem;
display:flex;
align-items:center;
justify-content:space-between;
`

const ItemImage = styled.div `
width:55px;
height:120px;
background-image:url('https://img.ssensemedia.com/images/b_white,g_center,f_auto,q_auto:best/231912M202000_1/butler-svc-ssense-exclusive-blue-formula-hoodie.jpg');
background-position:center;
background-size:cover;
`

const ItemDescription = styled.div `
display:flex;
flex-direction:column;
margin-left:40px;
`

const Title = styled.div `
font-weight:800;
`

const Size = styled.div `
color:grey;
`

const ItemPrice = styled.div  `
&::before {
	content:'$'
}
` 


const OrderTotalInfo = styled.div `
height:60px;
width:100%;
padding:30px 0;
padding-left:100px;
box-sizing:border-box;
`

const OrderDetail =styled.div `
display:flex;
justify-content:space-between;
`

const Detail = styled.div `
font-size:0.7rem;
`

const Div = styled.div `
display:flex;
align-items:center;
`

const Seller = styled.div `
font-size:0.8rem;
margin-top:40px;
`

const OrderTotalDetail = styled(OrderDetail) `
font-weight:900;
`

export default function ShoppingCart () {

	return (
		<>
			<Header />
			<Navbar />
			<ShoppingCartWrapper>
				<ItemsPart>
					<ItemsWrapper>
						<SingleOrderSection/>
						<OrderTotalInfo>
							<OrderDetail>
								<Detail>Total</Detail>
								<Detail>30000</Detail>
							</OrderDetail>
							<OrderDetail>
								<Detail>Duties & Taxes</Detail>
								<Detail>300</Detail>
							</OrderDetail>
							<OrderTotalDetail>
								<Detail>Order Total</Detail>
								<Detail>30300</Detail>
							</OrderTotalDetail>
						</OrderTotalInfo>
					</ItemsWrapper>
				</ItemsPart>
				<InfoPart></InfoPart>
			</ShoppingCartWrapper>
		</>	
	)
}
